// src/App.js
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { useState, useEffect } from 'react';

import Navbar from './components/Navbar';
import ProtectedRoute from './components/ProtectedRoute';
import NotFound from './pages/NotFound';
import LazyWithTimeout from './components/LazyWithTimeout';

const Login = React.lazy(() => import('./pages/Login'));
const Register = React.lazy(() => import('./pages/Register'));
const Destinations = React.lazy(() => import('./pages/Destinations'));
const MyGroups = React.lazy(() => import('./pages/MyGroups'));
const GroupDetails = React.lazy(() => import('./pages/GroupDetails'));
const CreateGroup = React.lazy(() => import('./components/CreateGroup'));

function App() {
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    document.body.classList.toggle('dark-mode', darkMode);
  }, [darkMode]);

  return (
    <Router>
      <div className={`app-container ${darkMode ? 'dark' : ''}`}>
        <Navbar darkMode={darkMode} setDarkMode={setDarkMode} />

        <Routes>
          <Route
            path="/"
            element={
              <LazyWithTimeout>
                <Login />
              </LazyWithTimeout>
            }
          />
          <Route
            path="/register"
            element={
              <LazyWithTimeout>
                <Register />
              </LazyWithTimeout>
            }
          />
          <Route
            path="/destinations"
            element={
              <LazyWithTimeout>
                <ProtectedRoute>
                  <Destinations />
                </ProtectedRoute>
              </LazyWithTimeout>
            }
          />
          <Route
            path="/my-groups"
            element={
              <LazyWithTimeout>
                <ProtectedRoute>
                  <MyGroups />
                </ProtectedRoute>
              </LazyWithTimeout>
            }
          />
          <Route
            path="/groups/:groupId"
            element={
              <LazyWithTimeout>
                <ProtectedRoute>
                  <GroupDetails />
                </ProtectedRoute>
              </LazyWithTimeout>
            }
          />
          <Route
            path="/create-group"
            element={
              <LazyWithTimeout>
                <ProtectedRoute>
                  <CreateGroup />
                </ProtectedRoute>
              </LazyWithTimeout>
            }
          />
          <Route path="/not-found" element={<NotFound />} />
          <Route path="*" element={<NotFound />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
